/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(InventTransferOrders, GroupIdLine), FormControlEventType::Modified)]
public static void GroupIdLine_OnModified(FormControl sender, FormControlEventArgs e)
{

    InventTransferLine                  inventTransferLine;
    ETG_TransferOrderQualitySpec        transferOrderQualitySpec;
    ETG_QualitySubGrpView               qualitySubGrpView;
    Name                                grpId   = sender.valueStr();

    FormDataSource  inventTransferLine_ds   = sender.formRun().dataSource(formDataSourceStr(InventTransferOrders,InventTransferLine))  as FormDataSource;
    inventTransferLine                      = inventTransferLine_ds.cursor();

    while select * from qualitySubGrpView
        where qualitySubGrpView.GroupID == grpId
    {
        transferOrderQualitySpec.MinRange            = qualitySubGrpView.MinRange;
        transferOrderQualitySpec.MaxRange            = qualitySubGrpView.MaxRange;
        transferOrderQualitySpec.AdjustmentType      = qualitySubGrpView.AdjustmentType;
        transferOrderQualitySpec.Increment           = qualitySubGrpView.Increment;
        transferOrderQualitySpec.FixedValue          = qualitySubGrpView.FixedValue;
        transferOrderQualitySpec.SubGroupID          = qualitySubGrpView.SubGroupID;
        transferOrderQualitySpec.InventTransId       = inventTransferLine.InventTransId;
        transferOrderQualitySpec.TransferId          = inventTransferLine.TransferId;
        transferOrderQualitySpec.GroupID             = qualitySubGrpView.GroupID;
        transferOrderQualitySpec.GroupDescription    = qualitySubGrpView.GroupDescription;
        transferOrderQualitySpec.SubGroupDescription = qualitySubGrpView.SubGroupDescription;
        transferOrderQualitySpec.insert();
    }
}
